# Windows ISO Debloat Script
# Dựa trên Windows-ISO-Debloater repository
# Tác giả: Generated by AI Assistant
# Mô tả: Script để debloat Windows ISO và tạo unattended setup

param(
    [Parameter(Mandatory=$true)]
    [string]$InputPath,
    
    [Parameter(Mandatory=$true)]
    [string]$OutputPath,
    
    [Parameter(Mandatory=$false)]
    [switch]$IsVerbose,
    
    [Parameter(Mandatory=$false)]
    [string]$WindowsVersion = "11",
    
    [Parameter(Mandatory=$false)]
    [switch]$SkipTelemetryRemoval = $false,
    
    [Parameter(Mandatory=$false)]
    [switch]$SkipBloatwareRemoval = $false,
    
    [Parameter(Mandatory=$false)]
    [switch]$DryRun = $false
)

# Cấu hình logging
$LogFile = Join-Path $OutputPath "debloat.log"
$ErrorLogFile = Join-Path $OutputPath "debloat-errors.log"

function Write-Log {
    param([string]$Message, [string]$Level = "INFO")
    $timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
    $logMessage = "[$timestamp] [$Level] $Message"
    
    if ($IsVerbose) {
        Write-Host $logMessage
    }
    
    Add-Content -Path $LogFile -Value $logMessage
}

function Write-ErrorLog {
    param([string]$Message, [string]$Exception = "")
    $timestamp = Get-Date -Format "yyyy-MM-dd HH:mm:ss"
    $errorMessage = "[$timestamp] ERROR: $Message"
    if ($Exception) {
        $errorMessage += " Exception: $Exception"
    }
    
    Write-Host $errorMessage -ForegroundColor Red
    Add-Content -Path $ErrorLogFile -Value $errorMessage
}

